import java.util.ArrayList;

public class Main {

    static boolean isPrime(int number) {
        if (number < 2) return false;

        for (int i = 2; (long) i * i <= number; i++) {
            if (number % i == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println("1-50 arasindaki asal sayilar:");
        ArrayList<Integer> primes = new ArrayList<>();

        for (int i = 1; i <= 50; i++) {
            if (isPrime(i)) {
                primes.add(i);
            }
        }

        System.out.println(primes);
        System.out.println("\nToplam asal sayi adedi: " + primes.size());

        // Tekil kontrol
        int testNumber = 97;
        System.out.println("\n" + testNumber + " asal mi: " + isPrime(testNumber));

        testNumber = 100;
        System.out.println(testNumber + " asal mi: " + isPrime(testNumber));
    }
}
